namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(new[]
        {
            new NotificationItem { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new NotificationItem { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new NotificationItem { Id = _nextId++, Message = "New feature available: dark mode.", Timestamp = DateTime.UtcNow.AddMinutes(-2) },
        });

        // Simulate new notifications arriving over time
        _ = Task.Run(async () =>
        {
            var messages = new[]
            {
                "You have a new follower.",
                "Your report is ready.",
                "Server maintenance scheduled.",
                "New comment on your post.",
                "Payment received successfully.",
                "Reminder: meeting in 30 minutes.",
            };
            var index = 0;
            while (true)
            {
                await Task.Delay(TimeSpan.FromSeconds(7));
                lock (_lock)
                {
                    _notifications.Add(new NotificationItem
                    {
                        Id = _nextId++,
                        Message = messages[index % messages.Length],
                        Timestamp = DateTime.UtcNow
                    });
                }
                index++;
            }
        });
    }

    public List<NotificationItem> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    public List<NotificationItem> GetSince(int lastId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastId).ToList();
        }
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in _notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @notification.Message
                <small class="text-muted">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationItem> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial notifications during prerender AND interactive init.
        // On the interactive pass the same data is loaded (no double-fetch issue
        // because this is a cheap in-memory call, and the polling hasn't started).
        _notifications = NotificationService.GetAll();
        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires on the interactive runtime — not during
            // static SSR prerender. Safe to start the polling loop here.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            if (ct.IsCancellationRequested) break;

            var newItems = NotificationService.GetSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                _lastSeenId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

